#include<bits/stdc++.h>
using namespace std;
const int MAXN=1e+6;
vector<int> p[MAXN];
int n,m;
bool vis[MAXN];
queue<int> q;
void DFS(int x){
    cout<<x<<' ';
    for(int i=0,sz=p[x].size();i<sz;i++)
        if(!vis[p[x][i]]){vis[p[x][i]]=true;DFS(p[x][i]);}
}
void BFS() {
    memset(vis,0,sizeof(vis));
    vis[1]=true;
    q.push(1);
    while(q.size()){
        int x=q.front();
        q.pop();
        cout<<x<<' ';
        for(int i=0,sz=p[x].size();i<sz;i++)
            if(!vis[p[x][i]])vis[p[x][i]]=true,q.push(p[x][i]);
    }
}
int main(void){
	int u,v;cin>>n>>m;
    for(int i=1;i<=m;i++)cin>>u>>v,p[u].push_back(v);
    for(int i=1;i<=n;i++)sort(p[i].begin(),p[i].end());
    vis[1]=true;DFS(1);cout<<"\n";BFS();
    return false;
}
